4231	[Counit is iso from two global generating families]
4232	  \label{lem:isIso_fromTildeGamma_of_genSections}
4233	  \lean{AlgebraicGeometry.isIso_fromTildeΓ_of_genSections}
4234	  \uses{lem:isIso_fromTildeGamma_of_presentation}
4235	  Let \(X = \operatorname{Spec} R\) and \(\mathcal{F}\) an \(\mathcal{O}_X\)-module.
4236	  Suppose given a global generating family
4237	  \(\sigma : \mathcal{F}.\mathrm{GeneratingSections}\) (an epimorphism
4238	  \(\sigma.\pi : \mathcal{O}_X^{(I)} \twoheadrightarrow \mathcal{F}\)) and a global
4239	  generating family \(\tau : (\operatorname{Ker} \sigma.\pi).\mathrm{GeneratingSections}\)
4240	  of its kernel. Then the tilde--\(\Gamma\) counit
4241	  \(\operatorname{fromTilde\Gamma} : \widetilde{\Gamma(X, \mathcal{F})} \to \mathcal{F}\)
4242	  is an isomorphism.
4243	\end{lemma}
4244	\begin{proof}
4245	  \uses{lem:isIso_fromTildeGamma_of_presentation}
4246	  \leanok
4247	  The two generating families assemble into a global presentation of \(\mathcal{F}\): the
4248	  composite \(\mathcal{O}_X^{(J)} \xrightarrow{\tau.\pi} \operatorname{Ker} \sigma.\pi
4249	  \hookrightarrow \mathcal{O}_X^{(I)} \xrightarrow{\sigma.\pi} \mathcal{F}\) is a global
4250	  exact sequence \(\mathcal{O}_X^{(J)} \to \mathcal{O}_X^{(I)} \to \mathcal{F} \to 0\),
4251	  i.e.\ the data \(\mathcal{F}.\mathrm{Presentation}\). Feeding this presentation to
4252	  Lemma~\ref{lem:isIso_fromTildeGamma_of_presentation} makes
4253	  \(\operatorname{fromTilde\Gamma}\) an isomorphism.
4254	\end{proof}
